import * as THREE from 'three';
import './css/style.css';
import MainBrain from './js/MainBrain';

// three.js r91 has addAttribute; three-bas 2.13+ calls setAttribute (added in r125)
if (!THREE.BufferGeometry.prototype.setAttribute) {
    THREE.BufferGeometry.prototype.setAttribute = THREE.BufferGeometry.prototype.addAttribute;
}

// eslint-disable-next-line
new MainBrain()



